126	            }
127	            lastKnownMetrics = metrics
128	            logger.log(
129	                .info,
130	                "Codex fetched \(metrics.count) metric(s) for account=\(account) via \(source.rawValue)"
131	            )
132	            return [VendorUsageEntry(
133	                vendor: vendor,
134	                account: account,
135	                isActive: true,
136	                lastAcquiredOn: ISODate(date: Date()),
137	                lastError: nil,
138	                metrics: metrics
139	            )]
140	        } catch {
141	            logger.log(.error, "Codex response parse failed: \(error)")
