4	public actor UsagesFileManager {
5	    // Internal init so tests can create isolated instances via @testable import.
6	    // Production code must use `UsagesFileManager.shared`.
7	    public static let shared = UsagesFileManager()
8	
9	    nonisolated public let filePath: String
10	    nonisolated public let lockPath: String
11	    private let logger: FileLogger
12	    private let lockTimeoutSeconds: TimeInterval
13	
14	    init(
15	        filePath: String? = nil,
16	        logger: FileLogger = Loggers.app,
17	        lockTimeoutSeconds: TimeInterval = 5.0
18	    ) {
19	        let home = FileManager.default.homeDirectoryForCurrentUser.path
20	        self.filePath = filePath ?? "\(home)/.cache/ai-usages-tracker/usages.json"
21	        self.logger = logger
22	        self.lockPath = self.filePath + ".lock"
23	        self.lockTimeoutSeconds = lockTimeoutSeconds
24	
25	        let dir = (self.filePath as NSString).deletingLastPathComponent
26	        do {
27	            try FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true, attributes: nil)
28	        } catch {
29	            logger.log(.error, "Failed to create directory \(dir): \(error)")
30	        }
31	    }
32	
33	    // MARK: - Public
34	
35	    public func read() async -> UsagesFile {
36	        do {
37	            return try await withFileLock(mode: LOCK_SH) { readUnsafe() }
38	        } catch is CancellationError {
39	            return UsagesFile()
40	        } catch {
41	            logger.log(.warning, "flock read failed — returning empty file: \(error)")
42	            return UsagesFile()
43	        }
44	    }
45	
46	    public func update(with entries: [VendorUsageEntry]) async {
47	        await update(with: entries, outagesByVendor: [:])
48	    }
49	
50	    /// Applies a usage merge plus per-vendor outage replacement in a single locked read-modify-write.
51	    ///
52	    /// Outage policy per vendor key in `outagesByVendor`:
53	    /// - present, non-empty list → replaces all outages of that vendor
54	    /// - present, empty list → removes all outages of that vendor ("all clear")
55	    /// - absent → outages of that vendor are preserved as-is (fetch failed, or no connector for it)
56	    public func update(
57	        with entries: [VendorUsageEntry],
58	        outagesByVendor: [Vendor: [Outage]]
59	    ) async {
60	        do {
61	            try await withFileLock(mode: LOCK_EX) {
62	                var file = readUnsafe()
63	                file = merge(existing: file, incoming: entries)
64	                if !outagesByVendor.isEmpty {
65	                    file.outages = applyOutageReplacement(
66	                        existing: file.outages,
67	                        replacements: outagesByVendor
68	                    )
69	                }
70	                writeUnsafe(file)
71	            }
72	        } catch is CancellationError {
73	            return
74	        } catch {
75	            logger.log(.warning, "flock update failed — skipping write: \(error)")
76	        }
77	    }
78	
79	    // MARK: - Active-account update
80	
81	    public func updateIsActive(vendor: Vendor, activeAccount: AccountEmail?) async {
82	        do {
83	            try await withFileLock(mode: LOCK_EX) {
84	                var file = readUnsafe()
85	                var changed = false
86	                for i in file.usages.indices where file.usages[i].vendor == vendor {
87	                    let newActive = file.usages[i].account == activeAccount
88	                    if file.usages[i].isActive != newActive {
89	                        file.usages[i].isActive = newActive
90	                        changed = true
91	                    }
92	                }
93	                if changed {
94	                    writeUnsafe(file)
95	                }
96	            }
97	        } catch is CancellationError {
98	            return
99	        } catch {
100	            logger.log(.warning, "flock updateIsActive failed — skipping: \(error)")
101	        }
102	    }
103	
104	    public func removeAccountUnknownPlaceholders() async -> Bool {
105	        do {
106	            return try await withFileLock(mode: LOCK_EX) {
