2	
3	public actor UsagePoller {
4	    public let connectors: [any UsageConnector]
5	    public let statusConnectors: [any StatusConnector]
6	    public let fileManager: UsagesFileManager
7	    private let logger: FileLogger
8	    private let refreshState: RefreshState?
9	    // Set once at init and never mutated; nonisolated to allow cross-actor reads
10	    // without sending through actor isolation (the @MainActor conformance of
11	    // AppPreferences makes it Sendable).
12	    private nonisolated let preferences: (any AppPreferences)?
13	    /// Fallback interval used when no preferences store is injected (e.g. tests).
14	    private let fixedInterval: Duration?
15	
16	    private var pollingTask: Task<Void, Never>?
17	
18	    /// Production initializer — reads refresh interval from preferences on each tick
19	    /// so changes take effect without restarting the poller.
20	    public init(
21	        connectors: [any UsageConnector],
22	        statusConnectors: [any StatusConnector] = [],
23	        fileManager: UsagesFileManager = UsagesFileManager.shared,
24	        logger: FileLogger = Loggers.app,
25	        refreshState: RefreshState? = nil,
26	        preferences: any AppPreferences
27	    ) {
28	        self.connectors = connectors
29	        self.statusConnectors = statusConnectors
30	        self.fileManager = fileManager
31	        self.logger = logger
32	        self.refreshState = refreshState
33	        self.preferences = preferences
34	        self.fixedInterval = nil
35	    }
36	
37	    /// Test/legacy initializer — uses a fixed interval instead of preferences.
38	    public init(
39	        connectors: [any UsageConnector],
40	        statusConnectors: [any StatusConnector] = [],
41	        interval: Duration = .seconds(180),
42	        fileManager: UsagesFileManager = UsagesFileManager.shared,
43	        logger: FileLogger = Loggers.app,
44	        refreshState: RefreshState? = nil
45	    ) {
46	        self.connectors = connectors
47	        self.statusConnectors = statusConnectors
48	        self.fileManager = fileManager
49	        self.logger = logger
50	        self.refreshState = refreshState
51	        self.preferences = nil
52	        self.fixedInterval = interval
53	    }
54	
55	    /// Resolves the current polling interval — reads from preferences (main actor hop)
56	    /// or falls back to the fixed interval.
57	    private func currentInterval() async -> Duration {
58	        if let preferences {
59	            return await MainActor.run { preferences.refreshInterval.duration }
60	        }
61	        return fixedInterval ?? .seconds(180)
62	    }
63	
64	    public func start() {
65	        guard pollingTask == nil else {
66	            logger.log(.warning, "Poller already running")
67	            return
68	        }
69	        pollingTask = Task {
70	            while !Task.isCancelled {
71	                await self.pollOnce()
72	                // Re-read interval each tick so settings changes take effect immediately.
73	                let sleepDuration = await self.currentInterval()
74	                try? await Task.sleep(for: sleepDuration)
75	                guard !Task.isCancelled else { break }
76	            }
77	        }
78	    }
79	
80	    public func stop() {
81	        pollingTask?.cancel()
82	        pollingTask = nil
83	        logger.log(.info, "Poller stopped")
84	    }
85	
86	    public func pollOnce(now: Date = Date(), force: Bool = false) async {
87	        logger.log(.debug, "Poll tick — fetching from \(connectors.count) connector(s)\(force ? " (forced)" : "")")
88	
89	        let existingFile = await fileManager.read()
90	        let currentInterval = await self.currentInterval()
91	        let intervalSeconds = Double(currentInterval.components.seconds)
92	        var skippedCount = 0
93	        let log = self.logger
94	
95	        let refreshState = self.refreshState
96	        let entries: [VendorUsageEntry] = await withTaskGroup(of: [VendorUsageEntry].self) { group in
97	            for connector in connectors {
98	                let account = connector.resolveActiveAccount()
99	                if !force,
100	                   let account,
101	                   let cached = existingFile.usages.first(where: { $0.vendor == connector.vendor && $0.account == account }),
102	                   let acquiredDate = cached.lastAcquiredOn?.date,
103	                   now.timeIntervalSince(acquiredDate) < intervalSeconds {
104	                    let age = Int(now.timeIntervalSince(acquiredDate))
105	                    logger.log(.debug, "Skipping \(connector.vendor)/\(account) — fresh (age \(age)s < \(Int(intervalSeconds))s)")
106	                    skippedCount += 1
107	                    continue
108	                }
109	                let refreshKey = account.map { AccountKey(vendor: connector.vendor, account: $0) }
110	                if let refreshKey {
111	                    await refreshState?.begin(refreshKey)
112	                }
113	                group.addTask {
114	                    let result: [VendorUsageEntry]
115	                    do {
116	                        result = try await connector.fetchUsages()
117	                    } catch {
118	                        log.log(.error, "Connector \(connector.vendor) threw: \(error)")
119	                        result = []
120	                    }
121	                    if let refreshKey {
122	                        await refreshState?.end(refreshKey)
123	                    }
124	                    return result
125	                }
126	            }
127	            var all: [VendorUsageEntry] = []
128	            for await batch in group {
129	                all.append(contentsOf: batch)
130	            }
131	            return all
132	        }
133	
134	        // Status connectors run on every tick (no freshness cache) and in parallel with usages.
135	        // Vendors whose fetch fails are omitted from the map so their prior outages survive.
136	        let statusLog = self.logger
137	        let outagesByVendor: [Vendor: [Outage]] = await withTaskGroup(
138	            of: (Vendor, Result<[Outage], Error>).self
139	        ) { group in
140	            for statusConnector in statusConnectors {
141	                group.addTask {
142	                    do {
143	                        let outages = try await statusConnector.fetchOutages()
144	                        return (statusConnector.vendor, .success(outages))
145	                    } catch {
146	                        return (statusConnector.vendor, .failure(error))
147	                    }
148	                }
149	            }
150	            var byVendor: [Vendor: [Outage]] = [:]
151	            for await (vendor, result) in group {
152	                switch result {
153	                case .success(let outages):
154	                    byVendor[vendor] = outages
155	                case .failure(let error):
156	                    statusLog.log(.warning, "Status fetch failed for \(vendor): \(error) — preserving existing outages")
157	                }
158	            }
159	            return byVendor
160	        }
