5	/// Sheet hosting the tester sign-off form. Composes a comment body,
6	/// copies it to the system pasteboard, opens the GitHub issue in the
7	/// default browser, and reveals the connector log in Finder so the
8	/// tester can drag-attach it. See `docs/ASSISTANT-ONBOARDING.md` §6.4.
9	///
10	/// The form is intentionally feature-light: no GitHub authentication,
11	/// no log-file scanning (the connector's `PayloadSanitizing` is the
12	/// single source of truth for what counts as confidential), no
13	/// posting via the GitHub REST API. The browser hand-off is the
14	/// simplest reliable bridge that does not introduce a credential
15	/// surface area.
16	struct TesterFeedbackSheet: View {
17	    let context: TesterFeedbackContext
18	    let displayName: String
