20	    let connectorLogURL: URL
21	    let onDismiss: () -> Void
22	    let submitter: TesterFeedbackSubmitting
23	
24	    @State private var plan: TesterFeedbackComment.Input.Plan = .pro
25	    @State private var planOtherDescription: String = ""
26	    @State private var checklistStates: [Bool]
27	    @State private var notes: String = ""
28	    @State private var didSubmit: Bool = false
29	
30	    init(
31	        context: TesterFeedbackContext,
32	        displayName: String,
33	        macOSVersion: String,
34	        connectorLogURL: URL,
35	        submitter: TesterFeedbackSubmitting = SystemTesterFeedbackSubmitter(),
36	        onDismiss: @escaping () -> Void
37	    ) {
38	        self.context = context
39	        self.displayName = displayName
40	        self.macOSVersion = macOSVersion
41	        self.connectorLogURL = connectorLogURL
42	        self.submitter = submitter
43	        self.onDismiss = onDismiss
44	        _checklistStates = State(initialValue: Array(repeating: false, count: Self.checklistLabels.count))
45	    }
46	
47	    private static let checklistLabels: [String] = [
48	        "Active account is detected correctly",
49	        "At least one usage metric matches the vendor's own dashboard within reasonable tolerance",
50	        "Reset date displayed in the popover matches the vendor's reported reset",
51	        "Optional: outage banner appears when the vendor reports an incident",
52	    ]
