5	// MARK: - URL mocking
6	
7	// swiftlint:disable:next w4_unchecked_sendable — URLProtocol subclass; all mutable static state accessed only from the serialized test suite
8	final class CodexMockURLProtocol: URLProtocol, @unchecked Sendable {
9	    nonisolated(unsafe) static var handler: ((URLRequest) -> (Data, HTTPURLResponse))?
10	    nonisolated(unsafe) static var capturedRequest: URLRequest?
11	    nonisolated(unsafe) static var errorToThrow: Error?
12	
13	    override class func canInit(with request: URLRequest) -> Bool { true }
14	    override class func canonicalRequest(for request: URLRequest) -> URLRequest { request }
15	
16	    override func startLoading() {
17	        Self.capturedRequest = request
18	        if let error = Self.errorToThrow {
19	            client?.urlProtocol(self, didFailWithError: error)
20	            return
21	        }
22	        guard let handler = Self.handler else {
23	            client?.urlProtocolDidFinishLoading(self)
24	            return
25	        }
26	        let (data, response) = handler(request)
27	        client?.urlProtocol(self, didReceive: response, cacheStoragePolicy: .notAllowed)
28	        client?.urlProtocol(self, didLoad: data)
29	        client?.urlProtocolDidFinishLoading(self)
30	    }
31	
32	    override func stopLoading() {}
33	}
34	
35	// MARK: - Auth mock
36	
37	private struct MockCodexAuth: CodexCredentialLocating {
38	    let credentials: CodexCredentials?
